const PILLARS=['interests','actors','tools','narrative','results','feedback'];
const COLORS={interests:'var(--p1)',actors:'var(--p2)',tools:'var(--p3)',narrative:'var(--p4)',results:'var(--p5)',feedback:'var(--p6)'};
const SETTINGS_KEY='jarbou3i-model-settings';
function readSettings(){try{return JSON.parse(localStorage.getItem(SETTINGS_KEY)||'{}')||{}}catch{return {}}}
function writeSettings(patch){try{localStorage.setItem(SETTINGS_KEY,JSON.stringify({...readSettings(),...patch}))}catch{}}
const savedSettings=readSettings();
let state={lang:['ar','en','fr'].includes(savedSettings.lang)?savedSettings.lang:'ar',stage:'topic',topic:'',context:'',analysisLang:['ar','en','fr'].includes(savedSettings.lang)?savedSettings.lang:'ar',assistant:'chatgpt',promptMode:'simple',analysis:null,jsonValid:false,activeReview:'overview',activePillar:null,lastPrompt:''};
const $=id=>document.getElementById(id);const t=(k)=>k.split('.').reduce((o,p)=>o&&o[p],I18N[state.lang])||k;
function syncLanguageShell(){
  document.documentElement.lang=state.lang;
  document.documentElement.dir=state.lang==='ar'?'rtl':'ltr';
  $('langAr')?.classList.toggle('active',state.lang==='ar');
  $('langEn')?.classList.toggle('active',state.lang==='en');
  $('langFr')?.classList.toggle('active',state.lang==='fr');
}
function setLang(lang){
  if(!['ar','en','fr'].includes(lang))return;
  state.lang=lang;
  state.analysisLang=lang;
  writeSettings({lang});
  renderAll();
  refreshDynamicMessages();
}
function applyI18n(){
  syncLanguageShell();
  document.title=`${t('appTitle')} — Jarbou3i Model`;
  document.querySelectorAll('[data-i18n]').forEach(el=>{el.textContent=t(el.dataset.i18n)});
  document.querySelectorAll('[data-i18n-placeholder]').forEach(el=>{el.placeholder=t(el.dataset.i18nPlaceholder)});
  document.querySelectorAll('[data-i18n-option]').forEach(el=>{el.textContent=t(el.dataset.i18nOption)});
  document.querySelectorAll('[data-i18n-title]').forEach(el=>{const txt=t(el.dataset.i18nTitle);el.title=txt;el.setAttribute('aria-label',txt)});
  const seg=$('languageSegment'); if(seg) seg.setAttribute('aria-label',t('languageLabel'));
}
function refreshDynamicMessages(){
  validateJsonInput();
  const status=$('topicStatus');
  if(!status) return;
  if(state.stage==='topic'){
    status.className='status warn';
    status.textContent=t('topicStatusStart');
  }else if(state.stage==='import'){
    status.className=state.lastPrompt?'status good':'status warn';
    status.textContent=state.lastPrompt?t('promptCopied'):t('topicStatusStart');
  }else if(state.stage==='review'){
    status.className='status good';
    status.textContent=t('analysisImported');
  }
}
function toast(msg,kind=''){const el=$('toast');el.textContent=msg;el.className='toast show';setTimeout(()=>el.classList.remove('show'),2600)}
