async function copyText(text){try{if(navigator.clipboard&&window.isSecureContext){await navigator.clipboard.writeText(text);return true}}catch{}try{const ta=document.createElement('textarea');ta.value=text;ta.style.position='fixed';ta.style.opacity='0';document.body.appendChild(ta);ta.focus();ta.select();const ok=document.execCommand('copy');ta.remove();return ok}catch{return false}}
function normalizeArray(x){return Array.isArray(x)?x:[]}
function normalizeAnalysis(raw){const a=(raw&&typeof raw==='object')?raw:{};const out={schema_version:a.schema_version||a.schemaVersion||'1.0.0',analysis_id:a.analysis_id||a.analysisId||'',generated_at:a.generated_at||a.generatedAt||'',language:a.language||a.lang||'',model_mode:a.model_mode||a.modelMode||'',subject:a.subject||{},contradictions:a.contradictions||{},scenarios:a.scenarios||{},evidence:a.evidence||{},assumptions:a.assumptions||{},links:normalizeArray(a.links),quality_gate:a.quality_gate||a.qualityGate||{}};PILLARS.forEach(p=>out[p]=normalizeArray(a[p]));out.contradictions.items=normalizeArray(out.contradictions.items);out.scenarios.items=normalizeArray(out.scenarios.items);out.evidence.items=normalizeArray(out.evidence.items);out.assumptions.items=normalizeArray(out.assumptions.items);return out;}
function cleanJsonCandidate(s){return String(s||'').replace(/^\uFEFF/,'').trim().replace(/[“”]/g,'"').replace(/[‘’]/g,"'").replace(/,\s*([}\]])/g,'$1')}
function balancedJsonSlice(s){const text=String(s||'');let start=-1,open='',close='';for(let i=0;i<text.length;i++){if(text[i]==='{'){start=i;open='{';close='}';break}if(text[i]==='['){start=i;open='[';close=']';break}}if(start<0)return '';let depth=0,inStr=false,esc=false;for(let i=start;i<text.length;i++){const ch=text[i];if(inStr){if(esc){esc=false;continue}if(ch==='\\'){esc=true;continue}if(ch==='"')inStr=false;continue}if(ch==='"'){inStr=true;continue}if(ch===open)depth++;if(ch===close){depth--;if(depth===0)return text.slice(start,i+1)}}return text.slice(start)}
function extractJson(text){const raw=String(text||'').trim();if(!raw)throw new Error('empty');const attempts=[raw];const fence=raw.match(/```(?:json|JSON)?\s*([\s\S]*?)```/);if(fence)attempts.push(fence[1]);attempts.push(balancedJsonSlice(raw));for(const a of attempts){const cleaned=cleanJsonCandidate(a);if(!cleaned)continue;try{return JSON.parse(cleaned)}catch(e){try{return JSON.parse(cleaned.replace(/\/\/.*$/gm,'').replace(/\/\*[\s\S]*?\*\//g,''))}catch{}}}throw new Error('invalid')}
function validateJsonInput(){const text=$('jsonInput').value.trim();if(!text){state.jsonValid=false;$('importBtn').disabled=true;$('repairPromptBtn').disabled=true;$('jsonStatus').className='status';$('jsonStatus').textContent=t('jsonWaiting');$('pasteCard').classList.remove('ready','invalid');return null}try{const raw=extractJson(text);const analysis=normalizeAnalysis(raw);const has=PILLARS.some(p=>analysis[p].length)||analysis.contradictions.items.length||analysis.scenarios.items.length;if(!has)throw new Error('incomplete');state.jsonValid=true;$('importBtn').disabled=false;$('repairPromptBtn').disabled=false;$('jsonStatus').className='status good';const wasMessy=cleanJsonCandidate(text)!==JSON.stringify(raw)&&!/^[\s\n]*[\[{]/.test(text);$('jsonStatus').textContent=wasMessy?t('jsonAutoRecovered'):t('jsonValid');$('pasteCard').classList.add('ready');$('pasteCard').classList.remove('invalid');return analysis}catch(e){state.jsonValid=false;$('importBtn').disabled=true;$('repairPromptBtn').disabled=false;$('jsonStatus').className='status bad';$('jsonStatus').textContent=t('jsonParseProblem');$('pasteCard').classList.remove('ready');$('pasteCard').classList.add('invalid');return null}}
function buildSchema(lang=state.analysisLang,mode=state.promptMode){const ar=lang==='ar';const fr=lang==='fr';const label=ar?'أعد JSON صالحًا فقط بالبنية التالية':fr?'Retourne uniquement un JSON valide avec la structure suivante':'Return valid JSON only using this structure';const schema={schema_version:'1.1.0',analysis_id:'slug-or-short-id',generated_at:'YYYY-MM-DDTHH:mm:ssZ',language:'ar|en|fr',model_mode:mode,subject:{title:'string',context:'string',question:'string',executive_thesis:'string'},interests:[{id:'I1',name:'string',type:'strategic|economic|political|ideological',intensity:1,horizon:'short|medium|long',stakes:'marginal|important|existential',confidence:'high|medium|low',rationale:'string'}],actors:[{id:'A1',name:'string',category:'state|company|movement|institution|external|society|lobby',financial:1,decision_access:1,disruption_capacity:1,media_influence:1,confidence:'high|medium|low',rationale:'string'}],tools:[{id:'T1',name:'string',type:'military|economic|legal|diplomatic|media|technological|social',cost:1,risk:1,speed:1,reversibility:1,deniability:1,confidence:'high|medium|low',rationale:'string'}],narrative:[{id:'N1',name:'string',frame:'security|democracy|sovereignty|identity|prosperity|rights|other',coherence:1,media_alignment:1,public_acceptance:1,confidence:'high|medium|low',rationale:'string'}],results:[{id:'R1',name:'string',type:'direct|indirect|unintended',goal_achieved_pct:50,cost_benefit:1,power_balance_impact:'strengthened|neutral|weakened',confidence:'high|medium|low',rationale:'string'}],feedback:[{id:'F1',description:'string',adapts:'interests|actors|tools|narrative',speed:'fast|slow',confidence:'high|medium|low',rationale:'string'}],contradictions:{items:[{id:'C1',rhetoric:'string',contradiction_type:'rhetoric_vs_action|interest_vs_alliance|tool_vs_goal|result_vs_intention|claim_vs_evidence|internal_inconsistency',actions:['string'],affected_layers:['interests|actors|tools|narrative|results|feedback'],interpretation:'string',severity:1,confidence:'high|medium|low'}]},scenarios:{items:[{id:'S1',name:'string',probability:40,timeframe:'string',drivers:['string'],early_signals:['string'],disproven_if:['string'],rationale:'string'}]},quality_gate:{publication_risk:'low|medium|high',weakest_layer:'string',next_improvement:'string'}};if(mode==='expert'||mode==='research'){schema.evidence={items:[{id:'E1',claim:'string',basis:'observation|inference|estimate|source_based',source_title:'string',source_url:'string',source_date:'YYYY-MM-DD or unknown',source_type:'primary|official|academic|journalistic|dataset|other',source_note:'string',evidence_strength:1,confidence:'high|medium|low',uncertainty:'string',counter_evidence:'string'}]};schema.assumptions={items:[{id:'AS1',assumption:'string',risk:'low|medium|high',disproving_test:'string',implication_if_wrong:'string'}]};schema.links=[{from:'I1',to:'A1',relation:'motivates|uses|justifies|produces|adapts|contradicts',strength:1}];}if(mode==='research'){schema.source_discipline={minimum_source_based_evidence_items:3,minimum_counter_evidence_items:1,notes:'Prefer official, academic, dataset, or high-quality journalistic sources. Mark uncertainty explicitly.'};}return label+'\n'+JSON.stringify(schema,null,2);}
function buildPrompt(){const lang=$('analysisLang').value;state.analysisLang=lang;state.assistant=$('assistantPreset').value;state.promptMode=$('promptMode').value;state.topic=$('topicInput').value.trim();state.context=$('timeframeInput').value.trim();const ar=lang==='ar';const fr=lang==='fr';const modeText=state.promptMode==='research'? (ar?'بحثي: أضف أدلة مصدرية، أدلة مضادة، عدم يقين، وروابط سببية مرقمة.':fr?'Recherche : ajoute des preuves sourcées, des contre-preuves, de l’incertitude et des liens causaux identifiés.':'Research: include source-grounded evidence, counter-evidence, uncertainty, and ID-based causal links.') : state.promptMode==='expert'?(ar?'خبير: أضف الأدلة، الافتراضات، والروابط السببية.':fr?'Expert : ajoute des preuves, des hypothèses et des liens causaux.':'Expert: include evidence, assumptions, and causal links.'):(ar?'مركّز: ركّز على الطبقات الست، التناقضات، والسيناريوهات.':fr?'Ciblé : priorise les six couches, les contradictions et les scénarios.':'Focused: prioritize the six layers, contradictions, and scenarios.');
if(ar)return `أنت محلل استراتيجي صارم. حلّل الموضوع التالي باستخدام نموذج: مصالح → فاعلون → أدوات → سردية → نتائج → تغذية راجعة.

الموضوع: ${state.topic}
السياق: ${state.context||'غير محدد'}
النمط: ${modeText}

قواعد مهمة:
- اكتب كل محتوى التحليل باللغة العربية.
- لا تُرجع أي شرح خارج JSON.
- فرّق بين الملاحظة والاستنتاج والتقدير عندما يكون ذلك مطلوبًا.
- في التناقضات: إذا كانت نفس السردية/الخطاب ينتج عدة أفعال متناقضة، اجعلها مجموعة واحدة تحتوي actions متعددة.
- في السيناريوهات: أضف شروطًا واضحة تُضعف أو تُبطل السيناريو.
- قبل إخراج JSON النهائي، راجع داخليًا: الفاعلين المفقودين، السببية الأحادية، الافتراضات غير المدعومة، ضعف الأدلة، غياب الأدلة المضادة، وغياب شروط الإبطال.
- لا تكتب مراجعتك الداخلية؛ أخرج JSON المصحح فقط.

${buildSchema(lang,state.promptMode)}`;
if(fr)return `Tu es un analyste stratégique rigoureux. Analyse le sujet suivant avec le modèle : Intérêts → Acteurs → Outils → Narratif → Résultats → Rétroaction.

Sujet : ${state.topic}
Contexte : ${state.context||'non précisé'}
Mode : ${modeText}

Règles :
- Rédige tout le contenu de l’analyse en français.
- Retourne uniquement du JSON. Aucun texte explicatif en dehors du JSON.
- Sépare observation, inférence et estimation lorsque c’est pertinent.
- Dans les contradictions : si la même rhétorique/hypothèse produit plusieurs actions contradictoires, conserve une seule entrée avec plusieurs actions.
- Dans les scénarios : inclue des conditions claires qui affaibliraient ou réfuteraient chaque scénario.
- Avant le JSON final, audite silencieusement : acteurs manquants, monocausalité, hypothèses non étayées, preuves faibles, absence de contre-preuves et absence de réfutateurs.
- Ne montre pas cet audit interne ; retourne uniquement le JSON corrigé.

${buildSchema(lang,state.promptMode)}`;
return `You are a rigorous strategic analyst. Analyze the following topic using the model: Interests → Actors → Tools → Narrative → Results → Feedback.

Topic: ${state.topic}
Context: ${state.context||'not specified'}
Mode: ${modeText}

Rules:
- Write all analysis content in English.
- Return JSON only. No explanation outside JSON.
- Separate observation, inference, and estimate where requested.
- In contradictions: if the same rhetoric/hypothesis has multiple contradictory actions, keep it as one contradiction group with multiple actions.
- In scenarios: include clear conditions that would weaken or disprove each scenario.
- Before final JSON, silently audit for missing actors, monocausal reasoning, unsupported assumptions, weak evidence, absent counter-evidence, and missing falsifiers.
- Do not reveal the audit. Return only the corrected JSON.

${buildSchema(lang,state.promptMode)}`;}
